function debounce(e,t){let n;return function(...c){clearTimeout(n),n=setTimeout(()=>e.apply(this,c),t)}}function updateGridPlaceholders(){const e=document.querySelector(".categories-block__content");if(!e){console.warn("\u041A\u043E\u043D\u0442\u0435\u0439\u043D\u0435\u0440 .categories-block \u043D\u0435 \u043D\u0430\u0439\u0434\u0435\u043D");return}const t=e.querySelectorAll(".categories-block__item");e.querySelectorAll(".grid-placeholder").forEach(l=>l.remove());const o=getComputedStyle(e).gridTemplateColumns.split(" ").length;if(!o||o===0){console.warn("\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0438\u0442\u044C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043A\u043E\u043B\u043E\u043D\u043E\u043A");return}const s=Math.ceil(t.length/o),d=o*s-t.length;for(let l=0;l<d;l++){const r=document.createElement("div");r.classList.add("grid-placeholder"),e.appendChild(r)}}document.addEventListener("DOMContentLoaded",updateGridPlaceholders);const debouncedUpdate=debounce(updateGridPlaceholders,200);window.addEventListener("resize",debouncedUpdate);
